indian_forts = {
    'Mughal': ['Red Fort (Delhi)', 'Agra Fort (Uttar Pradesh)', 'Fatehpur Sikri Fort (Uttar Pradesh)'],
    'Rajput': ['Amber Fort (Jaipur)', 'Mehrangarh Fort (Jodhpur)', 'Chittorgarh Fort (Rajasthan)'],
    'Dravidian': ['Golconda Fort (Hyderabad)', 'Vellore Fort (Tamil Nadu)', 'Gingee Fort (Tamil Nadu)'],
    'Islamic': ['Daulatabad Fort (Maharashtra)', 'Diu Fort (Diu)'],
    'Hindu': ['Jaisalmer Fort (Rajasthan)', 'Tipu Sultan\'s Summer Palace (Bangalore)'],
    'Island': ['Fort St. George (Andaman & Nicobar Islands)', 'Ross Island (Andaman & Nicobar Islands)']
}

def categorize_fort(architectural_style):
    return indian_forts.get(architectural_style, [])

# Example usage
print(categorize_fort('Mughal'))  # Output: ['Red Fort (Delhi)', 'Agra Fort (Uttar Pradesh)', ...]
